sp_widget.client_script:
api.controller=function($scope,spUtil,$rootScope,spModal) {

	var c = this;
    c.rules = c.data.rules;

	$rootScope.$broadcast('earningRulesUpdated', {
    earningrulescount: c.rules.length
	});

    c.formatCondition = function(condition) {
        if (!condition) return "No conditions";

        return condition.split("^").map(function(cond) {
            return cond
                .replace("=", " = ")
                .replace(/_/g, " "); // makes column_01 → column 01
        }).join(" AND ");
    };

    c.removeRule = function(index) {
        c.rules.splice(index, 1);
    };

	c.deleteRecord= function(rulesysid)
	{
		c.data.action="deleteRecord";
		c.data.rulesysid= rulesysid;

		spModal.open({
					title: 'Delete Confirmation',
					message: 'This action cannot be undone. Are you sure?',
					buttons: [
							{label: 'Cancel', cancel: true},
							{label: 'Delete', primary: true}
					]
			}).then(function() {
					c.server.update().then(function(response){
							if(response.status==true)
								{
									spUtil.addInfoMessage("Record deleted successfully.");
											spUtil.update($scope).then(function() {	
										c.rules = c.data.rules;
										$rootScope.$broadcast('earningRulesUpdated', {
											earningrulescount: c.rules.length
										});

									});
								}
								else
												spUtil.addErrorMessage("No Authorization to perform the action");
														});
									});



	};

		// listen for refresh event
			$scope.$on("earningruleupdation", function(event, data) {
				 	spUtil.update($scope).then(function() {	
					c.rules = c.data.rules;
					$rootScope.$broadcast('earningRulesUpdated', {
						earningrulescount: c.rules.length
					});

				});
			});

			/*c.editRecord = function(rulesysid)
			{
				if(c.data.status=="draft")
				window.location.href="?id=incentnow_form&table=x_ctans_incentnow_earning_rule&sys_id="+rulesysid;
				else
					spUtil.addErrorMessage("Related Plan should be in draft state for editing.")
			} */


		c.editRecord = function(rulesysid) {
				if (c.data.status == "draft") {
					$rootScope.$broadcast("earningrule.edit", {
					sys_id: rulesysid
				});
								} else {
					spUtil.addErrorMessage("Related Plan should be in draft state for editing.");
				}
			};



};

