sp_widget.script:
(function() {

    data.rules = [];	
    var planSysId = $sp.getParameter('sys_id');
    data.plan_sys_id = planSysId || "-1"; 
		data.table= $sp.getParameter('table') || "";

	if(data.table && data.plan_sys_id)
		{
			var grPlan= new GlideRecordSecure(data.table);
			if(grPlan.get(data.plan_sys_id))
				{
					data.status=grPlan.getValue("status");
				}

			var grEarn = new GlideRecordSecure('x_ctans_incentnow_earning_rule');

			if (planSysId) {
					grEarn.addQuery('plan', planSysId); // reference field
					grEarn.addQuery('active', true); // optional
					grEarn.orderByDesc('sys_created_on');
					grEarn.query();

					while (grEarn.next()) {

							data.rules.push({
									sys_id: grEarn.getUniqueValue(),
									name: grEarn.getDisplayValue('rule_name'),
									aggregation: grEarn.getDisplayValue('aggregation'),
									source: grEarn.getDisplayValue('source_object'),
									field: grEarn.getDisplayValue('field'),
									condition: grEarn.getValue('condition_query_display'),
									earning_level: grEarn.getDisplayValue('earning_level'),
									plan: grEarn.getDisplayValue('plan'),
									status: grEarn.getDisplayValue('status'),
							});
					}
			}
		}

	if(input && input.action=="deleteRecord")
		{
			var grearning = new GlideRecordSecure('x_ctans_incentnow_earning_rule');
			if(grearning.get(input.rulesysid))
				{
					data.status=grearning.deleteRecord();
				}


		}





})();
